package iata

import (
	"database/sql/driver"
	"strings"
)

type Iata struct {
	Country, Code, Region, City, Airport string
	Latitude, Longitude                  float64
}

func (iata Iata) String() string {
	return iata.Code
}

// Scan implements the sql.Scanner interface.
func (iata *Iata) Scan(value any) error {
	i := ToIata(value.(string))
	iata.Country = i.Country
	iata.Code = i.Code
	iata.Region = i.Region
	iata.City = i.City
	iata.Airport = i.Airport
	iata.Latitude = i.Latitude
	iata.Longitude = i.Longitude
	return nil
}

// Value implements the driver.Valuer interface.
func (iata Iata) Value() (driver.Value, error) {
	if len(iata.Code) == 0 {
		return IataUnknown, nil
	}

	return iata.Code, nil
}

